var Stufe, Abstand, Abholung, Einleitung, Artikel, Verb, Folgetermin, Meldung;

// Beschreibe diese Funktion …
async function Pushover_senden(Stufe) {
  Abstand = getState('trashschedule.0.next.daysLeft').val;
  Abholung = getState('trashschedule.0.next.typesText').val;
  if (!(getState('trashschedule.0.next.dateFound').val && Abstand <= 1)) {
    console.debug((['Kein Mülltermin gefunden. Stufe: ',Stufe,'; nächste Abholung: ',Abholung,' in ',Abstand,' Tagen.'].join('')));
  } else {
    if (Stufe == 3 && Abstand != 0) {
      // Die morgendliche Erinnerung läuft nur am Abholtag
      console.debug((['Mülltermin gefunden, sollte ignoriert werden, aber Nachfolgetermin am nächsten Tag gefunden. Stufe: ',Stufe,'; Abstand ',Abstand,'.'].join('')));
    } else if (Stufe <= 2 && Abstand == 0 && getState('trashschedule.0.nextAfter.daysLeft').val) {
      // Die vor- und nachmittägliche Erinnerung am Abholtag unterdrücken - es sei denn, am Folgetag gibt es eine weitere Abholung
      console.debug((['Mülltermin gefunden, aber ignoriert. Stufe: ',Stufe,'; Abstand ',Abstand,'.'].join('')));
    } else {

      switch (Stufe) {
      	case 1:
        Einleitung = 'Morgen ';

      		break;
      	case 2:
        Einleitung = 'Mülltonne schon draußen? Morgen ';

      		break;
      	case 3:
        Einleitung = 'Letzte Chance zur Entsorgung! Heute ';

      		break;
      }

      switch (Abholung) {
      	case 'Altpapier':
        Artikel = 'wird das ';

      		break;
      	case 'Biotonne':
        Artikel = 'wird die ';

      		break;
      	case 'Gartenabfälle':
        Artikel = 'werden ';

      		break;
      	case 'Gelbe Tonne':
        Artikel = 'wird die ';

      		break;
      	case 'Hausmüll':
        Artikel = 'wird der ';

      		break;
      	case 'Schadstoffmobil':
        Artikel = 'kommt das ';

      		break;
      	case 'Weihnachtsbäume':
        Artikel = 'werden ';

      		break;
      	default:
        Artikel = 'werden ';

      		break;
      }
      if (Abholung == 'Schadstoffmobil') {
        Verb = '. ';
      } else {
        Verb = ' abgeholt. ';
      }
      if (getState('trashschedule.0.nextAfter.dateFound').val) {
        Folgetermin = ['Nachfolgender Termin:  ',getState('trashschedule.0.nextAfter.typesText').val,' am ',getState('trashschedule.0.nextAfter.dateFormat').val,' (',getState('trashschedule.0.nextAfter.daysLeft').val,' Tage).'].join('');
      } else {
        Folgetermin = 'Keine weiteren Termine gefunden; prüfe Abfallkalender!';
      }
      Meldung = [Einleitung,Artikel,Abholung,Verb,Folgetermin].join('');
      console.debug(('Mülltermin gefunden! Sende: ' + String(Meldung)));
      sendTo('telegram.0', 'send', {
        text: Meldung,
      });
    }
  }
}


// Um 10:00 Uhr am Vortag (verbleibende Tage = 1) erinnern, dass Abholung bevorsteht
schedule("0 10 * * *", async () => {
  await Pushover_senden(1);
});
// Um 18:00 Uhr am Vortag (verbleibende Tage = 1) erinnern, dass Abholung bevorsteht
schedule("0 18 * * *", async () => {
  await Pushover_senden(2);
});
// Um 07:00 Uhr am Abholtag (verbleibende Tage = 0) erinnern, dass Abholung bevorsteht
schedule("0 7 * * *", async () => {
  await Pushover_senden(3);
});
// Sende aktuellen Status auf Anfrage
on({ id: [].concat(['0_userdata.0.trigger.scripts.erinnerungen.müllabfuhr']), val: true }, async (obj) => {
  let value = obj.state.val;
  let oldValue = obj.oldState.val;
  sendTo('telegram.0', 'send', {
    text: (['Nächster Termin:  ',getState('trashschedule.0.next.typesText').val,' am ',getState('trashschedule.0.next.dateFormat').val,' (',getState('trashschedule.0.next.daysLeft').val,' Tage).','\n','Übernächster Termin:  ',getState('trashschedule.0.nextAfter.typesText').val,' am ',getState('trashschedule.0.nextAfter.dateFormat').val,' (',getState('trashschedule.0.nextAfter.daysLeft').val,' Tage).'].join('')),
  });
  setState('0_userdata.0.trigger.scripts.erinnerungen.müllabfuhr' /* müllabfuhr */, false);
});


